CSS_ANIMATIONS.keyframes_css:
@keyframes blood-drip {
  0% {
    background-position: 0% -100%;
  }
  50% {
    background-position: 0% 0%;
  }
  100% {
    background-position: 0% 100%;
  }
}

.animate-blood-drip {
  background: linear-gradient(90deg, #000000 0%, #1c1c1c 10%, #8b0000 30%, #ff2200 45%, #ffd700 60%, #d4af37 75%, #c0c0c0 90%, #000000 100%);
  background-size: 100% 300%;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  animation: blood-drip 3s ease-in-out infinite;
  position: relative;
}

/* Hiệu ứng giọt máu rơi */
.animate-blood-drip::before {
  content: '';
  position: absolute;
  bottom: -20px;
  left: 50%;
  width: 4px;
  height: 0;
  background: #ff2200;
  border-radius: 50%;
  animation: drip-drop 1.5s ease-in infinite;
}

@keyframes drip-drop {
  0% {
    height: 0;
    opacity: 0;
  }
  50% {
    height: 20px;
    opacity: 1;
  }
  100% {
    height: 0;
    opacity: 0;
    transform: translateY(10px);
  }
}

@keyframes bubble-float {
  0% {
    transform: translateY(0) scale(1);
    opacity: 0;
  }
  20% {
    opacity: 0.8;
  }
  80% {
    opacity: 0.8;
  }
  100% {
    transform: translateY(-50px) scale(1.2);
    opacity: 0;
  }
}

.animate-bubble {
  background: linear-gradient(90deg, #000000 0%, #1c1c1c 10%, #8b0000 30%, #ff2200 45%, #ffd700 60%, #d4af37 75%, #c0c0c0 90%, #000000 100%);
  background-size: 200% auto;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  animation: water-ripple 3s ease infinite;
  position: relative;
  display: inline-block;
}

/* Tạo nhiều bong bóng */
.animate-bubble {
  position: relative;
}

.animate-bubble::before,
.animate-bubble::after {
  content: '○';
  position: absolute;
  color: rgba(192, 192, 192, 0.6);
  font-size: 12px;
  animation: bubble-float 2s ease-in infinite;
  pointer-events: none;
}

.animate-bubble::before {
  left: 10%;
  animation-delay: 0s;
}

.animate-bubble::after {
  right: 15%;
  animation-delay: 0.7s;
}

/* Thêm bong bóng thứ 3 */
.bubble-extra {
  position: absolute;
  content: '○';
  color: rgba(255, 215, 0, 0.5);
  font-size: 8px;
  animation: bubble-float 2.5s ease-in infinite;
  animation-delay: 1.2s;
  left: 50%;
}

@keyframes glitch-crack {
  0%, 100% {
    transform: skew(0deg, 0deg);
    text-shadow: 0 0 0px rgba(255, 0, 0, 0);
  }
  20% {
    transform: skew(2deg, 1deg);
    text-shadow: -2px 0px 2px rgba(255, 34, 0, 0.5);
  }
  40% {
    transform: skew(-2deg, -1deg);
    text-shadow: 2px 0px 2px rgba(255, 215, 0, 0.5);
  }
  60% {
    transform: skew(1deg, 2deg);
  }
  80% {
    transform: skew(-1deg, -2deg);
  }
}

.animate-crack {
  background: linear-gradient(90deg, #000000 0%, #1c1c1c 10%, #8b0000 30%, #ff2200 45%, #ffd700 60%, #d4af37 75%, #c0c0c0 90%, #000000 100%);
  background-size: 200% auto;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  animation: glitch-crack 0.3s ease infinite;
  position: relative;
  display: inline-block;
}

@keyframes dynamic-gradient {
  0% {
    background-position: 0% 50%;
    transform: scale(1);
  }
  50% {
    background-position: 100% 50%;
    transform: scale(1.05);
  }
  100% {
    background-position: 0% 50%;
    transform: scale(1);
  }
}

.animate-dynamic {
  background: linear-gradient(90deg, #000000 0%, #1c1c1c 10%, #8b0000 30%, #ff2200 45%, #ffd700 60%, #d4af37 75%, #c0c0c0 90%, #000000 100%);
  background-size: 200% auto;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  animation: dynamic-gradient 4s ease infinite;
  display: inline-block;
  font-weight: bold;
}

@keyframes fire {
  0%   { text-shadow: 0 0 6px #ff4500, 0 -2px 12px #ff6a00, 0 -4px 20px #ffd000; filter: brightness(1); }
  25%  { text-shadow: 2px 0 8px #ff2200, -1px -4px 16px #ff8c00, 1px -6px 24px #ffe000; filter: brightness(1.1); }
  50%  { text-shadow: -2px 0 6px #ff4500, 2px -2px 10px #ffb300, 0px -8px 28px #ffec00; filter: brightness(1.2); }
  75%  { text-shadow: 1px 0 7px #ff3300, -2px -3px 14px #ff6a00, 2px -5px 22px #ffd000; filter: brightness(1.05); }
  100% { text-shadow: 0 0 6px #ff4500, 0 -2px 12px #ff6a00, 0 -4px 20px #ffd000; filter: brightness(1); }
}
.animate-fire {
  color: #ffcc00;
  animation: fire 1.5s ease-in-out infinite;
}

@keyframes rainbow-text-animation {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}
.animate-rainbow-text {
  background-size: 200% 200%;
  animation: rainbow-text-animation 5s ease infinite;
}

@keyframes slide-bg {
  0% {
    background-position: 0% 0%;
  }
  100% {
    background-position: 100% 0%;
  }
}

.animate-slide-bg {
  background-image: linear-gradient(
    45deg,
    #ff3c00,
    #ff9a00,
    #3c00ff,
    #ff3c00
  );
  background-size: 300% 100%;
  animation: slide-bg 6s linear infinite;
  color: white;
  padding: 12px 24px;
  border-radius: 16px;
}

@keyframes lightning-flash {
  0%, 100% {
    filter: brightness(1);
    text-shadow: 0 0 0px rgba(255, 215, 0, 0);
  }
  5% {
    filter: brightness(1.5);
    text-shadow: 0 0 20px rgba(255, 215, 0, 0.8);
  }
  10% {
    filter: brightness(1);
  }
  15% {
    filter: brightness(1.3);
    text-shadow: 0 0 15px rgba(255, 34, 0, 0.8);
  }
  20% {
    filter: brightness(1);
  }
}

.animate-thunder {
  background: linear-gradient(90deg, #000000 0%, #1c1c1c 10%, #8b0000 30%, #ff2200 45%, #ffd700 60%, #d4af37 75%, #c0c0c0 90%, #000000 100%);
  background-size: 200% auto;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  animation: lightning-flash 0.5s ease infinite;
  position: relative;
}

/* Tia sét */
.animate-thunder::before {
  content: '⚡';
  position: absolute;
  font-size: 30px;
  left: -20px;
  top: -10px;
  opacity: 0;
  animation: lightning-bolt 0.8s ease infinite;
}

@keyframes lightning-bolt {
  0%, 100% {
    opacity: 0;
    transform: translateX(-10px);
  }
  10% {
    opacity: 1;
    transform: translateX(0);
  }
  20% {
    opacity: 0;
    transform: translateX(10px);
  }
}

@keyframes water-ripple {
  0% {
    text-shadow: 0 0 0px rgba(192, 192, 192, 0);
    transform: scale(1);
  }
  50% {
    text-shadow: 0 0 10px rgba(192, 192, 192, 0.8), 0 0 20px rgba(255, 215, 0, 0.5);
    transform: scale(1.02);
  }
  100% {
    text-shadow: 0 0 0px rgba(192, 192, 192, 0);
    transform: scale(1);
  }
}

.animate-water-drop {
  background: linear-gradient(90deg, #000000 0%, #1c1c1c 10%, #8b0000 30%, #ff2200 45%, #ffd700 60%, #d4af37 75%, #c0c0c0 90%, #000000 100%);
  background-size: 200% auto;
  background-clip: text;
  -webkit-background-clip: text;
  color: transparent;
  animation: water-ripple 2s ease-in-out infinite;
  position: relative;
  display: inline-block;
}

/* Giọt nước rơi */
.animate-water-drop::after {
  content: '💧';
  position: absolute;
  font-size: 20px;
  opacity: 0;
  animation: water-fall 1.5s ease-in infinite;
  pointer-events: none;
}

@keyframes water-fall {
  0% {
    opacity: 0;
    transform: translateY(-20px) translateX(-10px);
  }
  20% {
    opacity: 1;
  }
  80% {
    opacity: 1;
  }
  100% {
    opacity: 0;
    transform: translateY(30px) translateX(5px);
  }
}

@keyframes wave-float {
    0%, 100% { transform: translateY(0px) rotate(0deg); }
    25%       { transform: translateY(-10px) rotate(-1deg); }
    75%       { transform: translateY(6px) rotate(1deg); }
  }
  .animate-wave-float {
    display: inline-block;
    color: #fff;
    animation: wave-float 3s ease-in-out infinite;
  }
